// Generated by OrchestKit Claude Plugin
// Created: 2026-05-22

/**
 * Tests for the SessionStart registrar hook (#1912).
 *
 * Isolated DB per test via ORK_SESSION_DB. Covers:
 *   - INSERT writes the row with expected status='running'
 *   - Sweep flips stale (>24h) running rows to 'crashed'
 *   - Sweep deletes expired locks
 *   - Re-running with the same sid is idempotent
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { DatabaseSync } from 'node:sqlite';

import { sessionRegistrar, __internals } from '../../lifecycle/session-registrar.js';
import { openDb, __resetDbForTests } from '../../lib/session-registry.js';
import { NOOP_CTX } from '../../lib/context.js';
import type { HookInput } from '../../types.js';

function makeInput(sid: string, projectDir: string): HookInput {
  return {
    hook_event: 'SessionStart',
    tool_name: '',
    session_id: sid,
    tool_input: {},
    project_dir: projectDir,
  } as HookInput;
}

describe('lifecycle/session-registrar (#1912)', () => {
  let workDir: string;
  let dbPath: string;
  let prevDbEnv: string | undefined;

  beforeEach(() => {
    workDir = mkdtempSync(join(tmpdir(), 'ork-registrar-'));
    dbPath = join(workDir, 'sessions.db');
    prevDbEnv = process.env.ORK_SESSION_DB;
    process.env.ORK_SESSION_DB = dbPath;
    __resetDbForTests();
  });

  afterEach(() => {
    __resetDbForTests();
    if (prevDbEnv === undefined) delete process.env.ORK_SESSION_DB;
    else process.env.ORK_SESSION_DB = prevDbEnv;
    rmSync(workDir, { recursive: true, force: true });
  });

  it('inserts a session row on SessionStart', () => {
    const input = makeInput('s-fresh', workDir);
    const result = sessionRegistrar(input, NOOP_CTX);
    expect(result.continue).toBe(true);

    const db = new DatabaseSync(dbPath, { readOnly: true });
    const row = db
      .prepare('SELECT sid, status, pid FROM sessions WHERE sid=?')
      .get('s-fresh') as { sid: string; status: string; pid: number } | undefined;
    db.close();
    expect(row?.sid).toBe('s-fresh');
    expect(row?.status).toBe('running');
    expect(row?.pid).toBe(process.pid);
  });

  it('is idempotent — running twice updates rather than fails', () => {
    sessionRegistrar(makeInput('s-dup', workDir), NOOP_CTX);
    __resetDbForTests();
    sessionRegistrar(makeInput('s-dup', workDir), NOOP_CTX);

    const db = new DatabaseSync(dbPath, { readOnly: true });
    const { count } = db
      .prepare("SELECT COUNT(*) AS count FROM sessions WHERE sid='s-dup'")
      .get() as { count: number };
    db.close();
    expect(count).toBe(1);
  });

  it('sweeps stale running rows to status=crashed', () => {
    // Pre-seed a stale row (last_heartbeat = now - 90,000 seconds, >24h ago).
    const db = openDb();
    const stale = Math.floor(Date.now() / 1000) - 90_000;
    db.prepare(
      `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, started_at, last_heartbeat, status)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
    ).run('s-stale', 9999, workDir, 'h-stale', workDir, stale, stale, 'running');
    db.close();
    __resetDbForTests();

    // Run the registrar — its sweep should mark s-stale as crashed.
    sessionRegistrar(makeInput('s-active', workDir), NOOP_CTX);

    const db2 = new DatabaseSync(dbPath, { readOnly: true });
    const staleRow = db2
      .prepare('SELECT status FROM sessions WHERE sid=?')
      .get('s-stale') as { status: string };
    const activeRow = db2
      .prepare('SELECT status FROM sessions WHERE sid=?')
      .get('s-active') as { status: string };
    db2.close();
    expect(staleRow.status).toBe('crashed');
    expect(activeRow.status).toBe('running');
  });

  // --- Peer-collision awareness (#2242) -------------------------------------

  /** Seed a live peer row in the same repo_hash + branch + main working tree. */
  function seedPeer(opts: {
    sid: string;
    repoHash: string;
    branch: string | null;
    worktreePath?: string | null;
    heartbeatAgeSec?: number;
    status?: string;
  }): void {
    const db = openDb();
    const now = Math.floor(Date.now() / 1000);
    db.prepare(
      `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, worktree_path, branch, started_at, last_heartbeat, status)
       VALUES (?, 4242, '/x', ?, '/x', ?, ?, ?, ?, ?)`,
    ).run(
      opts.sid,
      opts.repoHash,
      opts.worktreePath ?? null,
      opts.branch,
      now,
      now - (opts.heartbeatAgeSec ?? 0),
      opts.status ?? 'running',
    );
    db.close();
    __resetDbForTests();
  }

  /** repo_hash the registrar will compute for workDir (mirrors hashRepo). */
  function repoHashFor(dir: string): string {
    return __internals.hashRepo(__internals.getRepoPath(dir));
  }

  it('warns when a live peer shares repo + branch + main working tree', () => {
    // workDir is not a git repo, so the registrar would derive branch=null;
    // drive findPeers directly with a known branch to exercise the collision path.
    const repoHash = repoHashFor(workDir);
    seedPeer({ sid: 's-peer', repoHash, branch: 'feature-x' });

    const db = openDb();
    const peers = __internals.findPeers(db, {
      sid: 's-me',
      repoHash,
      branch: 'feature-x',
      worktreePath: null,
      nowSec: Math.floor(Date.now() / 1000),
    });
    db.close();
    expect(peers.map(p => p.sid)).toEqual(['s-peer']);

    const warning = __internals.formatPeerWarning(peers, '/repo/myproj', 'feature-x');
    expect(warning).toContain('myproj-task');
    expect(warning).toContain('git worktree add');
    expect(warning).toContain('feature-x');
  });

  it('does NOT warn when this session is worktree-isolated', () => {
    const repoHash = repoHashFor(workDir);
    seedPeer({ sid: 's-peer', repoHash, branch: 'feature-x' });
    const db = openDb();
    const peers = __internals.findPeers(db, {
      sid: 's-me',
      repoHash,
      branch: 'feature-x',
      worktreePath: '/some/worktree', // isolated → safe
      nowSec: Math.floor(Date.now() / 1000),
    });
    db.close();
    expect(peers).toEqual([]);
  });

  it('does NOT warn when the peer is on a different branch', () => {
    const repoHash = repoHashFor(workDir);
    seedPeer({ sid: 's-peer', repoHash, branch: 'other-branch' });
    const db = openDb();
    const peers = __internals.findPeers(db, {
      sid: 's-me',
      repoHash,
      branch: 'feature-x',
      worktreePath: null,
      nowSec: Math.floor(Date.now() / 1000),
    });
    db.close();
    expect(peers).toEqual([]);
  });

  it('does NOT warn about a stale peer (heartbeat older than the liveness window)', () => {
    const repoHash = repoHashFor(workDir);
    seedPeer({ sid: 's-peer', repoHash, branch: 'feature-x', heartbeatAgeSec: 600 });
    const db = openDb();
    const peers = __internals.findPeers(db, {
      sid: 's-me',
      repoHash,
      branch: 'feature-x',
      worktreePath: null,
      nowSec: Math.floor(Date.now() / 1000),
    });
    db.close();
    expect(peers).toEqual([]);
  });

  it('does NOT warn when there is no branch', () => {
    const repoHash = repoHashFor(workDir);
    seedPeer({ sid: 's-peer', repoHash, branch: null });
    const db = openDb();
    const peers = __internals.findPeers(db, {
      sid: 's-me',
      repoHash,
      branch: null,
      worktreePath: null,
      nowSec: Math.floor(Date.now() / 1000),
    });
    db.close();
    expect(peers).toEqual([]);
  });

  it('sweeps expired locks', () => {
    // Seed an active session + expired lock + non-expired lock.
    const db = openDb();
    const now = Math.floor(Date.now() / 1000);
    db.prepare(
      `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, started_at, last_heartbeat)
       VALUES ('s-holder', 1, '/x', 'h', '/x', ?, ?)`,
    ).run(now, now);
    db.prepare(
      `INSERT INTO locks (name, holder_sid, acquired_at, expires_at)
       VALUES ('expired', 's-holder', ?, ?)`,
    ).run(now - 1000, now - 100);
    db.prepare(
      `INSERT INTO locks (name, holder_sid, acquired_at, expires_at)
       VALUES ('alive', 's-holder', ?, ?)`,
    ).run(now, now + 1000);
    db.close();
    __resetDbForTests();

    sessionRegistrar(makeInput('s-new', workDir), NOOP_CTX);

    const db2 = new DatabaseSync(dbPath, { readOnly: true });
    const names = (db2
      .prepare('SELECT name FROM locks ORDER BY name')
      .all() as { name: string }[]).map(r => r.name);
    db2.close();
    expect(names).toEqual(['alive']);
  });
});
